package com.hfad.agencyapp.data;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

import com.hfad.agencyapp.ui.models.Customer;

import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Simple SQLiteOpenHelper for customers table. Uses TEXT id (UUID) to keep compatibility.
 */
public class CustomerDbHelper extends SQLiteOpenHelper {
    // Keep this separate from Room's agency_app.db to avoid schema conflicts.
    private static final String DATABASE_NAME = "customer_ui.db";
    // bumped to 4 to add address/payment methods while preserving legacy city data
    private static final int DATABASE_VERSION = 4;

    public static final String TABLE_CUSTOMERS = "customers";
    public static final String COL_ID = "id";
    public static final String COL_BUSINESS = "business_name";
    public static final String COL_CONTACT = "contact_person";
    public static final String COL_CITY = "city"; // legacy column retained for upgrade compatibility
    public static final String COL_ADDRESS = "address";
    // Optional fields
    public static final String COL_PHONE = "phone";
    public static final String COL_BR_NUMBER = "br_number";
    public static final String COL_ID_NUMBER = "id_number";
    public static final String COL_PAYMENT_METHODS = "payment_methods";

    public CustomerDbHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        // Create customers table with legacy city plus canonical address/payment columns.
        String sql = "CREATE TABLE " + TABLE_CUSTOMERS + " ("
                + COL_ID + " TEXT PRIMARY KEY,"
                + COL_BUSINESS + " TEXT,"
                + COL_CONTACT + " TEXT,"
                + COL_CITY + " TEXT,"
                + COL_ADDRESS + " TEXT,"
                + COL_PHONE + " TEXT,"
                + COL_BR_NUMBER + " TEXT,"
                + COL_ID_NUMBER + " TEXT,"
                + COL_PAYMENT_METHODS + " TEXT"
                + ");";
        db.execSQL(sql);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        // Migrate existing DB without dropping data.
        if (oldVersion < 4) {
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_ADDRESS + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_PHONE + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_BR_NUMBER + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_ID_NUMBER + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_PAYMENT_METHODS + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("UPDATE " + TABLE_CUSTOMERS + " SET " + COL_ADDRESS + " = " + COL_CITY + " WHERE (" + COL_ADDRESS + " IS NULL OR " + COL_ADDRESS + " = '') AND " + COL_CITY + " IS NOT NULL");
            } catch (Exception ignored) {}
        }
    }

    // Insert or update
    public String insertCustomer(Customer c) {
        SQLiteDatabase db = getWritableDatabase();
        if (c.getId() == null || c.getId().isEmpty()) {
            c.setId(UUID.randomUUID().toString());
        }
        ContentValues cv = new ContentValues();
        cv.put(COL_ID, c.getId());
        cv.put(COL_BUSINESS, c.getBusinessName());
        cv.put(COL_CONTACT, c.getContactPerson());
        cv.put(COL_CITY, c.getAddress());
        cv.put(COL_ADDRESS, c.getAddress());
        // optional fields may be null
        cv.put(COL_PHONE, c.getPhone());
        cv.put(COL_BR_NUMBER, c.getBrNumber());
        cv.put(COL_ID_NUMBER, c.getIdNumber());
        cv.put(COL_PAYMENT_METHODS, c.getPaymentMethods());

        long res = db.insertWithOnConflict(TABLE_CUSTOMERS, null, cv, SQLiteDatabase.CONFLICT_REPLACE);
        return res == -1 ? null : c.getId();
    }

    public boolean deleteCustomer(String id) {
        SQLiteDatabase db = getWritableDatabase();
        int rows = db.delete(TABLE_CUSTOMERS, COL_ID + " = ?", new String[]{id});
        return rows > 0;
    }

    public List<Customer> getAllCustomers() {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, null, null, null, null, COL_BUSINESS + " ASC")) {
            while (cursor.moveToNext()) {
                list.add(cursorToCustomer(cursor));
            }
        }
        return list;
    }

    public Customer getCustomerById(String id) {
        SQLiteDatabase db = getReadableDatabase();
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, COL_ID + " = ?", new String[]{id}, null, null, null)) {
            if (cursor.moveToFirst()) {
                return cursorToCustomer(cursor);
            }
            return null;
        }
    }

    public List<Customer> searchCustomers(String query) {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        String q = "%" + query + "%";
        // include optional fields in search (phone, br number, id number)
        String selection = COL_BUSINESS + " LIKE ? OR " + COL_CONTACT + " LIKE ? OR " + COL_ADDRESS + " LIKE ? OR " + COL_CITY + " LIKE ?"
                + " OR " + COL_PHONE + " LIKE ? OR " + COL_BR_NUMBER + " LIKE ? OR " + COL_ID_NUMBER + " LIKE ?";
        String[] args = new String[]{q, q, q, q, q, q, q};
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, selection, args, null, null, COL_BUSINESS + " ASC")) {
            while (cursor.moveToNext()) {
                list.add(cursorToCustomer(cursor));
            }
        }
        return list;
    }

    private Customer cursorToCustomer(Cursor cursor) {
        String id = cursor.getString(cursor.getColumnIndexOrThrow(COL_ID));
        String business = cursor.getString(cursor.getColumnIndexOrThrow(COL_BUSINESS));
        String contact = cursor.getString(cursor.getColumnIndexOrThrow(COL_CONTACT));
        String address = null;
        int idx = cursor.getColumnIndex(COL_ADDRESS);
        if (idx != -1) address = cursor.getString(idx);
        if (address == null || address.isEmpty()) {
            idx = cursor.getColumnIndex(COL_CITY);
            if (idx != -1) address = cursor.getString(idx);
        }
        // optional fields may be null if not set
        String phone = null;
        String br = null;
        String idNum = null;
        idx = cursor.getColumnIndex(COL_PHONE);
        if (idx != -1) phone = cursor.getString(idx);
        idx = cursor.getColumnIndex(COL_BR_NUMBER);
        if (idx != -1) br = cursor.getString(idx);
        idx = cursor.getColumnIndex(COL_ID_NUMBER);
        if (idx != -1) idNum = cursor.getString(idx);
        String paymentMethods = null;
        idx = cursor.getColumnIndex(COL_PAYMENT_METHODS);
        if (idx != -1) paymentMethods = cursor.getString(idx);

        return new Customer(id, business, contact, address, phone, br, idNum, paymentMethods);
    }
}

package com.hfad.agencyapp.data;

import android.content.ContentValues;
import android.content.Context;
import android.database.Cursor;
import android.database.sqlite.SQLiteDatabase;
import android.database.sqlite.SQLiteOpenHelper;

import com.hfad.agencyapp.ui.models.Customer;

import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

/**
 * Simple SQLiteOpenHelper for customers table. Uses TEXT id (UUID) to keep compatibility.
 */
public class CustomerDbHelper extends SQLiteOpenHelper {
    // Keep this separate from Room's agency_app.db to avoid schema conflicts.
    private static final String DATABASE_NAME = "customer_ui.db";
    // bumped to 5 to add blocked status column
    private static final int DATABASE_VERSION = 5;

    public static final String TABLE_CUSTOMERS = "customers";
    public static final String COL_ID = "id";
    public static final String COL_BUSINESS = "business_name";
    public static final String COL_CONTACT = "contact_person";
    public static final String COL_CITY = "city"; // legacy column retained for upgrade compatibility
    public static final String COL_ADDRESS = "address";
    // Optional fields
    public static final String COL_PHONE = "phone";
    public static final String COL_BR_NUMBER = "br_number";
    public static final String COL_ID_NUMBER = "id_number";
    public static final String COL_PAYMENT_METHODS = "payment_methods";
    public static final String COL_IS_BLOCKED = "is_blocked";

    public CustomerDbHelper(Context context) {
        super(context, DATABASE_NAME, null, DATABASE_VERSION);
    }

    @Override
    public void onCreate(SQLiteDatabase db) {
        // Create customers table with legacy city plus canonical address/payment columns.
        String sql = "CREATE TABLE " + TABLE_CUSTOMERS + " ("
                + COL_ID + " TEXT PRIMARY KEY,"
                + COL_BUSINESS + " TEXT,"
                + COL_CONTACT + " TEXT,"
                + COL_CITY + " TEXT,"
                + COL_ADDRESS + " TEXT,"
                + COL_PHONE + " TEXT,"
                + COL_BR_NUMBER + " TEXT,"
                + COL_ID_NUMBER + " TEXT,"
                + COL_PAYMENT_METHODS + " TEXT,"
                + COL_IS_BLOCKED + " INTEGER DEFAULT 0"
                + ");";
        db.execSQL(sql);
    }

    @Override
    public void onUpgrade(SQLiteDatabase db, int oldVersion, int newVersion) {
        // Migrate existing DB without dropping data.
        if (oldVersion < 5) {
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_IS_BLOCKED + " INTEGER DEFAULT 0");
            } catch (Exception ignored) {}
        }
        if (oldVersion < 4) {
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_ADDRESS + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_PHONE + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_BR_NUMBER + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_ID_NUMBER + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("ALTER TABLE " + TABLE_CUSTOMERS + " ADD COLUMN " + COL_PAYMENT_METHODS + " TEXT");
            } catch (Exception ignored) {}
            try {
                db.execSQL("UPDATE " + TABLE_CUSTOMERS + " SET " + COL_ADDRESS + " = " + COL_CITY + " WHERE (" + COL_ADDRESS + " IS NULL OR " + COL_ADDRESS + " = '') AND " + COL_CITY + " IS NOT NULL");
            } catch (Exception ignored) {}
        }
    }

    // Insert or update
    public String insertCustomer(Customer c) {
        SQLiteDatabase db = getWritableDatabase();
        if (c.getId() == null || c.getId().isEmpty()) {
            c.setId(UUID.randomUUID().toString());
        }
        ContentValues cv = new ContentValues();
        cv.put(COL_ID, c.getId());
        cv.put(COL_BUSINESS, c.getBusinessName());
        cv.put(COL_CONTACT, c.getContactPerson());
        cv.put(COL_CITY, c.getAddress());
        cv.put(COL_ADDRESS, c.getAddress());
        // optional fields may be null
        cv.put(COL_PHONE, c.getPhone());
        cv.put(COL_BR_NUMBER, c.getBrNumber());
        cv.put(COL_ID_NUMBER, c.getIdNumber());
        cv.put(COL_PAYMENT_METHODS, c.getPaymentMethods());
        cv.put(COL_IS_BLOCKED, c.isBlocked() ? 1 : 0);

        long res = db.insertWithOnConflict(TABLE_CUSTOMERS, null, cv, SQLiteDatabase.CONFLICT_REPLACE);
        return res == -1 ? null : c.getId();
    }

    public boolean deleteCustomer(String id) {
        SQLiteDatabase db = getWritableDatabase();
        int rows = db.delete(TABLE_CUSTOMERS, COL_ID + " = ?", new String[]{id});
        return rows > 0;
    }

    public List<Customer> getAllCustomers() {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, null, null, null, null, COL_BUSINESS + " ASC")) {
            while (cursor.moveToNext()) {
                list.add(cursorToCustomer(cursor));
            }
        }
        return list;
    }

    public Customer getCustomerById(String id) {
        SQLiteDatabase db = getReadableDatabase();
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, COL_ID + " = ?", new String[]{id}, null, null, null)) {
            if (cursor.moveToFirst()) {
                return cursorToCustomer(cursor);
            }
            return null;
        }
    }

    public List<Customer> searchCustomers(String query) {
        List<Customer> list = new ArrayList<>();
        SQLiteDatabase db = getReadableDatabase();
        String q = "%" + query + "%";
        // include optional fields in search (phone, br number, id number)
        String selection = COL_BUSINESS + " LIKE ? OR " + COL_CONTACT + " LIKE ? OR " + COL_ADDRESS + " LIKE ? OR " + COL_CITY + " LIKE ?"
                + " OR " + COL_PHONE + " LIKE ? OR " + COL_BR_NUMBER + " LIKE ? OR " + COL_ID_NUMBER + " LIKE ?";
        String[] args = new String[]{q, q, q, q, q, q, q};
        try (Cursor cursor = db.query(TABLE_CUSTOMERS, null, selection, args, null, null, COL_BUSINESS + " ASC")) {
            while (cursor.moveToNext()) {
                list.add(cursorToCustomer(cursor));
            }
        }
        return list;
    }

    private Customer cursorToCustomer(Cursor cursor) {
        String id = cursor.getString(cursor.getColumnIndexOrThrow(COL_ID));
        String business = cursor.getString(cursor.getColumnIndexOrThrow(COL_BUSINESS));
        String contact = cursor.getString(cursor.getColumnIndexOrThrow(COL_CONTACT));
        String address = null;
        int idx = cursor.getColumnIndex(COL_ADDRESS);
        if (idx != -1) address = cursor.getString(idx);
        if (address == null || address.isEmpty()) {
            idx = cursor.getColumnIndex(COL_CITY);
            if (idx != -1) address = cursor.getString(idx);
        }
        // optional fields may be null if not set
        String phone = null;
        String br = null;
        String idNum = null;
        idx = cursor.getColumnIndex(COL_PHONE);
        if (idx != -1) phone = cursor.getString(idx);
        idx = cursor.getColumnIndex(COL_BR_NUMBER);
        if (idx != -1) br = cursor.getString(idx);
        idx = cursor.getColumnIndex(COL_ID_NUMBER);
        if (idx != -1) idNum = cursor.getString(idx);
        String paymentMethods = null;
        idx = cursor.getColumnIndex(COL_PAYMENT_METHODS);
        if (idx != -1) paymentMethods = cursor.getString(idx);
        boolean isBlocked = false;
        idx = cursor.getColumnIndex(COL_IS_BLOCKED);
        if (idx != -1) isBlocked = cursor.getInt(idx) == 1;

        return new Customer(id, business, contact, address, phone, br, idNum, paymentMethods, isBlocked);
    }
}

package com.hfad.agencyapp.ui.adapters;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.DiffUtil;
import androidx.recyclerview.widget.ListAdapter;
import androidx.recyclerview.widget.RecyclerView;

import com.hfad.agencyapp.databinding.ItemCustomerBinding;
import com.hfad.agencyapp.ui.models.Customer;

import java.util.Objects;

/**
 * Adapter for customer list using ListAdapter + DiffUtil and ViewBinding.
 */
@SuppressWarnings("rawtypes")
public class CustomersAdapter extends ListAdapter<Customer, CustomersAdapter.CustomerViewHolder> {

    public interface OnCustomerActionListener {
        void onClick(Customer customer);
        void onLongClick(Customer customer, View anchor);
    }

    private final OnCustomerActionListener listener;

    public CustomersAdapter(OnCustomerActionListener listener) {
        super(new DiffUtil.ItemCallback<>() {
            @Override
            public boolean areItemsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return oldItem.getId() != null && oldItem.getId().equals(newItem.getId());
            }

            @Override
            public boolean areContentsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return Objects.equals(oldItem.getBusinessName(), newItem.getBusinessName())
                        && Objects.equals(oldItem.getContactPerson(), newItem.getContactPerson())
                        && Objects.equals(oldItem.getAddress(), newItem.getAddress())
                        && Objects.equals(oldItem.getPaymentMethods(), newItem.getPaymentMethods());
            }
        });
        this.listener = listener;
    }

    @NonNull
    @Override
    public CustomerViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        ItemCustomerBinding binding = ItemCustomerBinding.inflate(LayoutInflater.from(parent.getContext()), parent, false);
        return new CustomerViewHolder(binding);
    }

    @Override
    public void onBindViewHolder(@NonNull CustomerViewHolder holder, int position) {
        Customer c = getItem(position);
        holder.bind(c, listener);
    }

    static class CustomerViewHolder extends RecyclerView.ViewHolder {
        private final ItemCustomerBinding binding;

        CustomerViewHolder(ItemCustomerBinding binding) {
            super(binding.getRoot());
            this.binding = binding;
        }

        void bind(Customer c, OnCustomerActionListener listener) {
            binding.tvBusinessName.setText(c.getBusinessName());
            binding.tvContactPerson.setText(c.getContactPerson());
            binding.tvAddress.setText(c.getAddress());

            // Outstanding placeholder: 0.00
            binding.tvOutstandingLabel.setText(com.hfad.agencyapp.R.string.outstanding_label);
            binding.tvOutstandingAmount.setText(com.hfad.agencyapp.R.string.zero_amount);

            binding.getRoot().setOnClickListener(v -> listener.onClick(c));
            binding.getRoot().setOnLongClickListener(v -> {
                listener.onLongClick(c, v);
                return true;
            });
        }
    }
}

package com.hfad.agencyapp.ui.adapters;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;

import androidx.annotation.NonNull;
import androidx.recyclerview.widget.DiffUtil;
import androidx.recyclerview.widget.ListAdapter;
import androidx.recyclerview.widget.RecyclerView;

import com.hfad.agencyapp.databinding.ItemCustomerBinding;
import com.hfad.agencyapp.ui.models.Customer;

import java.util.Objects;

/**
 * Adapter for customer list using ListAdapter + DiffUtil and ViewBinding.
 */
public class CustomersAdapter extends ListAdapter<Customer, CustomersAdapter.CustomerViewHolder> {

    public interface OnCustomerActionListener {
        void onClick(Customer customer);
        void onLongClick(Customer customer, View anchor);
    }

    private final OnCustomerActionListener listener;

    public CustomersAdapter(OnCustomerActionListener listener) {
        super(new DiffUtil.ItemCallback<>() {
            @Override
            public boolean areItemsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return oldItem.getId() != null && oldItem.getId().equals(newItem.getId());
            }

            @Override
            public boolean areContentsTheSame(@NonNull Customer oldItem, @NonNull Customer newItem) {
                return Objects.equals(oldItem.getBusinessName(), newItem.getBusinessName())
                        && Objects.equals(oldItem.getContactPerson(), newItem.getContactPerson())
                        && Objects.equals(oldItem.getAddress(), newItem.getAddress())
                        && Objects.equals(oldItem.getPaymentMethods(), newItem.getPaymentMethods());
            }
        });
        this.listener = listener;
    }

    @NonNull
    @Override
    public CustomerViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        ItemCustomerBinding binding = ItemCustomerBinding.inflate(LayoutInflater.from(parent.getContext()), parent, false);
        return new CustomerViewHolder(binding);
    }

    @Override
    public void onBindViewHolder(@NonNull CustomerViewHolder holder, int position) {
        Customer c = getItem(position);
        holder.bind(c, listener);
    }

    static class CustomerViewHolder extends RecyclerView.ViewHolder {
        private final ItemCustomerBinding binding;

        CustomerViewHolder(ItemCustomerBinding binding) {
            super(binding.getRoot());
            this.binding = binding;
        }

        void bind(Customer c, OnCustomerActionListener listener) {
            binding.tvBusinessName.setText(c.getBusinessName());
            binding.tvContactPerson.setText(c.getContactPerson());
            binding.tvAddress.setText(c.getAddress());

            // Outstanding placeholder: 0.00
            binding.tvOutstandingLabel.setText(com.hfad.agencyapp.R.string.outstanding_label);
            binding.tvOutstandingAmount.setText(com.hfad.agencyapp.R.string.zero_amount);

            // Apply blocked styling if customer is blocked
            if (c.isBlocked()) {
                itemView.setAlpha(0.5f);
                itemView.setEnabled(false);
            } else {
                itemView.setAlpha(1.0f);
                itemView.setEnabled(true);
            }

            binding.getRoot().setOnClickListener(v -> listener.onClick(c));
            binding.getRoot().setOnLongClickListener(v -> {
                listener.onLongClick(c, v);
                return true;
            });
        }
    }
}

package com.hfad.agencyapp.ui.customers;

import android.os.Bundle;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import com.hfad.agencyapp.databinding.ActivityCustomerDetailBinding;
import com.hfad.agencyapp.ui.models.Customer;
import com.hfad.agencyapp.viewmodel.CustomerViewModel;

/**
 * Activity that displays detailed information about a selected customer.
 */
public class CustomerDetailActivity extends AppCompatActivity {
    private ActivityCustomerDetailBinding binding;
    private CustomerViewModel viewModel;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityCustomerDetailBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        setSupportActionBar(binding.toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setTitle("Customer Details");
        }
        binding.toolbar.setNavigationOnClickListener(v -> finish());

        viewModel = new ViewModelProvider(this).get(CustomerViewModel.class);

        String customerId = getIntent().getStringExtra("customer_id");
        if (customerId != null) {
            loadCustomerDetails(customerId);
        }
    }

    private void loadCustomerDetails(String customerId) {
        Customer customer = viewModel.getById(customerId);
        if (customer != null) {
            displayCustomerDetails(customer);
        }
    }

    private void displayCustomerDetails(Customer customer) {
        // Business Information
        binding.tvBusinessName.setText(customer.getBusinessName() != null ? customer.getBusinessName() : "-");
        binding.tvContactPerson.setText(customer.getContactPerson() != null ? customer.getContactPerson() : "-");
        binding.tvAddress.setText(customer.getAddress() != null ? customer.getAddress() : "-");

        // Contact Information
        binding.tvPhone.setText(customer.getPhone() != null && !customer.getPhone().isEmpty() ? customer.getPhone() : "-");

        // Additional Details
        binding.tvBrNumber.setText(customer.getBrNumber() != null && !customer.getBrNumber().isEmpty() ? customer.getBrNumber() : "-");
        binding.tvIdNumber.setText(customer.getIdNumber() != null && !customer.getIdNumber().isEmpty() ? customer.getIdNumber() : "-");

        // Payment Methods
        String paymentMethods = formatPaymentMethods(customer.getPaymentMethods());
        binding.tvPaymentMethods.setText(paymentMethods);
    }

    private String formatPaymentMethods(String paymentMethods) {
        if (paymentMethods == null || paymentMethods.trim().isEmpty()) {
            return "Cash, Credit, Cheque";
        }
        // Convert CSV format (CASH,CREDIT,CHEQUE) to readable format
        String[] methods = paymentMethods.split(",");
        StringBuilder formatted = new StringBuilder();
        for (int i = 0; i < methods.length; i++) {
            String method = methods[i].trim();
            // Capitalize first letter, lowercase rest
            formatted.append(method.substring(0, 1).toUpperCase())
                    .append(method.substring(1).toLowerCase());
            if (i < methods.length - 1) {
                formatted.append(", ");
            }
        }
        return formatted.toString();
    }
}

package com.hfad.agencyapp.ui.customers;

import android.os.Bundle;
import android.view.Menu;
import android.view.MenuItem;
import android.widget.Toast;
import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;
import com.google.android.material.snackbar.Snackbar;
import com.hfad.agencyapp.R;
import com.hfad.agencyapp.databinding.ActivityCustomerDetailBinding;
import com.hfad.agencyapp.ui.models.Customer;
import com.hfad.agencyapp.viewmodel.CustomerViewModel;

/**
 * Activity that displays detailed information about a selected customer.
 */
public class CustomerDetailActivity extends AppCompatActivity {
    private ActivityCustomerDetailBinding binding;
    private CustomerViewModel viewModel;
    private Customer currentCustomer;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        binding = ActivityCustomerDetailBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        setSupportActionBar(binding.toolbar);
        if (getSupportActionBar() != null) {
            getSupportActionBar().setDisplayHomeAsUpEnabled(true);
            getSupportActionBar().setTitle("Customer Details");
        }
        binding.toolbar.setNavigationOnClickListener(v -> finish());

        viewModel = new ViewModelProvider(this).get(CustomerViewModel.class);

        String customerId = getIntent().getStringExtra("customer_id");
        if (customerId != null) {
            loadCustomerDetails(customerId);
        }
    }

    private void loadCustomerDetails(String customerId) {
        currentCustomer = viewModel.getById(customerId);
        if (currentCustomer != null) {
            displayCustomerDetails(currentCustomer);
        }
    }

    private void displayCustomerDetails(Customer customer) {
        // Business Information
        binding.tvBusinessName.setText(customer.getBusinessName() != null ? customer.getBusinessName() : "-");
        binding.tvContactPerson.setText(customer.getContactPerson() != null ? customer.getContactPerson() : "-");
        binding.tvAddress.setText(customer.getAddress() != null ? customer.getAddress() : "-");

        // Contact Information
        binding.tvPhone.setText(customer.getPhone() != null && !customer.getPhone().isEmpty() ? customer.getPhone() : "-");

        // Additional Details
        binding.tvBrNumber.setText(customer.getBrNumber() != null && !customer.getBrNumber().isEmpty() ? customer.getBrNumber() : "-");
        binding.tvIdNumber.setText(customer.getIdNumber() != null && !customer.getIdNumber().isEmpty() ? customer.getIdNumber() : "-");

        // Payment Methods
        String paymentMethods = formatPaymentMethods(customer.getPaymentMethods());
        binding.tvPaymentMethods.setText(paymentMethods);

        // Update UI based on blocked status
        updateBlockedStatus();
    }

    private void updateBlockedStatus() {
        if (currentCustomer == null) return;

        // Apply visual styling if blocked
        if (currentCustomer.isBlocked()) {
            binding.getRoot().setAlpha(0.6f);
        } else {
            binding.getRoot().setAlpha(1.0f);
        }
        invalidateOptionsMenu();
    }

    @Override
    public boolean onCreateOptionsMenu(Menu menu) {
        getMenuInflater().inflate(R.menu.menu_customer_detail, menu);
        return true;
    }

    @Override
    public boolean onPrepareOptionsMenu(Menu menu) {
        if (currentCustomer != null) {
            MenuItem blockItem = menu.findItem(R.id.action_block);
            if (blockItem != null) {
                blockItem.setTitle(currentCustomer.isBlocked() ? "Unblock Customer" : "Block Customer");
            }
        }
        return true;
    }

    @Override
    public boolean onOptionsItemSelected(MenuItem item) {
        if (item.getItemId() == R.id.action_block) {
            toggleBlockStatus();
            return true;
        } else if (item.getItemId() == android.R.id.home) {
            finish();
            return true;
        }
        return super.onOptionsItemSelected(item);
    }

    private void toggleBlockStatus() {
        if (currentCustomer == null) return;

        currentCustomer.setBlocked(!currentCustomer.isBlocked());
        new Thread(() -> {
            boolean ok = viewModel.saveCustomer(currentCustomer);
            runOnUiThread(() -> {
                if (ok) {
                    updateBlockedStatus();
                    String message = currentCustomer.isBlocked() ? "Customer blocked" : "Customer unblocked";
                    Snackbar.make(binding.getRoot(), message, Snackbar.LENGTH_SHORT).show();
                } else {
                    Toast.makeText(this, "Failed to update customer status", Toast.LENGTH_SHORT).show();
                }
            });
        }).start();
    }

    private String formatPaymentMethods(String paymentMethods) {
        if (paymentMethods == null || paymentMethods.trim().isEmpty()) {
            return "Cash, Credit, Cheque";
        }
        // Convert CSV format (CASH,CREDIT,CHEQUE) to readable format
        String[] methods = paymentMethods.split(",");
        StringBuilder formatted = new StringBuilder();
        for (int i = 0; i < methods.length; i++) {
            String method = methods[i].trim();
            // Capitalize first letter, lowercase rest
            formatted.append(method.substring(0, 1).toUpperCase())
                    .append(method.substring(1).toLowerCase());
            if (i < methods.length - 1) {
                formatted.append(", ");
            }
        }
        return formatted.toString();
    }
}

package com.hfad.agencyapp.ui.invoice;

